/// and returns it.
/// Note that verification is still experimental and may not
/// catch every error, or be maximally performant. For the
/// previous, unchecked, behavior use
/// `root_as_tctr_value_table_unchecked`.
pub fn root_as_tctr_value_table(buf: &[u8]) -> Result<TCtrValueTable<'_>, ::flatbuffers::InvalidFlatbuffer> {
  ::flatbuffers::root::<TCtrValueTable>(buf)
}
#[inline]
/// Verifies that a buffer of bytes contains a size prefixed
/// `TCtrValueTable` and returns it.
/// Note that verification is still experimental and may not
/// catch every error, or be maximally performant. For the
/// previous, unchecked, behavior use
