pub fn size_prefixed_root_as_tctr_value_table(buf: &[u8]) -> Result<TCtrValueTable<'_>, ::flatbuffers::InvalidFlatbuffer> {
  ::flatbuffers::size_prefixed_root::<TCtrValueTable>(buf)
}
#[inline]
/// Verifies, with the given options, that a buffer of bytes
/// contains a `TCtrValueTable` and returns it.
/// Note that verification is still experimental and may not
/// catch every error, or be maximally performant. For the
/// previous, unchecked, behavior use
/// `root_as_tctr_value_table_unchecked`.
pub fn root_as_tctr_value_table_with_opts<'b, 'o>(
  opts: &'o ::flatbuffers::VerifierOptions,
  buf: &'b [u8],
) -> Result<TCtrValueTable<'b>, ::flatbuffers::InvalidFlatbuffer> {
  ::flatbuffers::root_with_opts::<TCtrValueTable<'b>>(opts, buf)
}
