#[inline]
/// Assumes, without verification, that a buffer of bytes contains a TCtrValueTable and returns it.
/// # Safety
/// Callers must trust the given bytes do indeed contain a valid `TCtrValueTable`.
pub unsafe fn root_as_tctr_value_table_unchecked(buf: &[u8]) -> TCtrValueTable<'_> {
  unsafe { ::flatbuffers::root_unchecked::<TCtrValueTable>(buf) }
}
#[inline]
